GameGetEquip = class()

function GameGetEquip:ctor(equipbox, initPos, yaw, actor, effect)
    self.entityId = 0
    self.equipbox = equipbox
    self.initPos = initPos
    self.yaw = yaw
    self.actor = actor
    self.haloEffect = effect or ""
    self.timer = 0
    self.isCreake = false
    self:onCreate()
end

function GameGetEquip:onCreate()
    local entityId = EngineWorld:addActorNpc(self.initPos, self.yaw, self.actor, function(entity)
        entity:setSkillName("idle")
        entity:setHaloEffectName(self.haloEffect)
    end)
    self.entityId = entityId
    GameManager:onAddGetEquipBox(self)
    if self.equipbox.config.type == 1 then
        local y = self.initPos.y + 2
        local pos = VectorUtil.newVector3(self.initPos.x, y, self.initPos.z)
        entityId = EngineWorld:addActorNpc(pos, self.yaw, self.equipbox.config.clothesActor, function(entity)
            entity:setSkillName("idle")
        end)
    else
        EngineWorld:addEntityItem(
                self.equipbox.config.armsId,
                1,
                0,
                5,
                VectorUtil.newVector3(self.initPos.x + 0.1, self.initPos.y + 1, self.initPos.z + 0.05),
                VectorUtil.ZERO,
                true,
                true)
        self.isCreake = true
    end
end

function GameGetEquip:onTick()

end

function GameGetEquip:onPlayerHit(player)
    self.equipbox:getEquip(player)
end

function GameGetEquip:onRemove()
    EngineWorld:removeEntity(self.entityId)
end

return GameGetEquip